// ── Group Classifier ──
export const prevGetGroup = c => {
  if (c.includes("Fluoride Varnish")) return "Fluoride Varnishes";
  if (c.includes("Fluoride Rinse") || c.includes("Fluoride Gel") || c.includes("Fluoride Toothpaste") || c.includes("5000 ppm")) return "Prescription Fluorides";
  if (c.includes("SDF") || c.includes("Silver Diamine")) return "Silver Diamine Fluoride";
  if (c.includes("Sealant")) return "Pit & Fissure Sealants";
  if (c.includes("Remineralization") || c.includes("CPP-ACP") || c.includes("Peptide") || c.includes("nHAP")) return "Remineralization Agents";
  if (c.includes("Xylitol") || c.includes("CHX") || c.includes("Chlorhexidine")) return "Adjunctive Agents";
  if (c.includes("Xerostomia") || c.includes("Dry Mouth") || c.includes("Sialagogue")) return "Xerostomia Management";
  if (c.includes("Protocol") || c.includes("Home Care") || c.includes("CRA")) return "Protocols & Home Care";
  return "Other";
};

